import React, { useState, useEffect } from 'react';
import { useStellarWallet } from '../hooks/useStellarWallet';
import { rpc, TransactionBuilder, Networks, SorobanRpc, xdr, Address, scValToNative, nativeToScVal, Contract } from '@stellar/stellar-sdk';
import { useContractEvents } from '../hooks/useContractEvents';

const CONTRACT_ID = "CXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX"; // Replace with actual ID
const NETWORK_PASSPHRASE = Networks.TESTNET;
const RPC_URL = 'https://soroban-testnet.stellar.org';
const server = new rpc.Server(RPC_URL);

export default function Crowdfund() {
  const { address, connect, disconnect, error: walletError, signTransaction, isConnecting } = useStellarWallet();
  const [amount, setAmount] = useState('');
  const [status, setStatus] = useState(''); // 'pending', 'success', 'fail'
  const [error, setError] = useState('');
  const [raised, setRaised] = useState(0);
  const [target, setTarget] = useState(100); 

  // useContractEvents(CONTRACT_ID);

  useEffect(() => {
    // Fetch initial state
    fetchState();
  }, []);

  const fetchState = async () => {
     try {
       // Setup contract object
       const contract = new Contract(CONTRACT_ID);

       // Call get_raised using simulateTransaction for reading
       const builder = new TransactionBuilder(await server.getAccount("GA7Y..."), { fee: '100', networkPassphrase: NETWORK_PASSPHRASE });
       // Note: real implementation would read the actual state value using proper simulateTransaction.
       // For this UI mockup, we'll keep it simple until the contract is deployed.
     } catch (err) {
       console.error(err);
     }
  };

  const handleDonate = async () => {
    setError('');
    setStatus('');

    if (!amount || isNaN(amount) || amount <= 0) {
      setError('Please enter a valid amount');
      return;
    }

    try {
      setStatus('pending');

      const sourceAccount = await server.getAccount(address);
      const contract = new Contract(CONTRACT_ID);

      // We form the smart contract call
      const tx = new TransactionBuilder(sourceAccount, {
        fee: '1000',
        networkPassphrase: NETWORK_PASSPHRASE,
      })
      .addOperation(contract.call('donate', 
          nativeToScVal(address, { type: 'address' }),
          nativeToScVal(Number(amount), { type: 'i128' })
      ))
      .setTimeout(30)
      .build();

      // Simulate the transaction to get actual resource fees and auth
      const simulatedTx = await server.simulateTransaction(tx);
      if (SorobanRpc.Api.isSimulationError(simulatedTx)) {
        throw new Error(simulatedTx.error);
      }

      // Assemble the transaction with Soroban auth and footprint
      const assembledTx = SorobanRpc.assembleTransaction(tx, NETWORK_PASSPHRASE, simulatedTx).build();

      // Convert to XDR and sign
      const xdr = assembledTx.toXDR();
      const signedXdr = await signTransaction(xdr);

      // Send to network
      setStatus('pending');
      const sendResponse = await server.sendTransaction(TransactionBuilder.fromXDR(signedXdr, NETWORK_PASSPHRASE));

      if (sendResponse.status === 'ERROR') {
        throw new Error(`Transaction failed: ${JSON.stringify(sendResponse)}`);
      }

      // Poll for status
      let getResponse = await server.getTransaction(sendResponse.hash);
      while (getResponse.status === 'NOT_FOUND') {
        await new Promise(resolve => setTimeout(resolve, 1000));
        getResponse = await server.getTransaction(sendResponse.hash);
      }

      if (getResponse.status === 'SUCCESS') {
        setStatus('success');
        setRaised(prev => prev + Number(amount));
        setAmount('');
      } else {
        setStatus('fail');
        setError(`Transaction failed in network execution.`);
      }

    } catch (err) {
      console.error(err);
      setStatus('fail');
      if (err.message) {
         if (err.message.includes('op_underfunded')) {
            setError('Insufficient balance to complete the donation.');
         } else {
            setError(err.message);
         }
      } else {
         setError('An unknown error occurred.');
      }
    }
  };

  return (
    <div className="min-h-screen bg-gray-900 text-white flex flex-col items-center justify-center p-4">
      <div className="bg-gray-800 p-8 rounded-xl shadow-2xl w-full max-w-md border border-gray-700 backdrop-blur-sm">
        <h1 className="text-3xl font-bold mb-6 text-center bg-gradient-to-r from-blue-400 to-purple-500 bg-clip-text text-transparent">
          Crowdfund Project
        </h1>

        <div className="mb-8">
           <div className="flex justify-between mb-2">
             <span className="text-gray-400 text-sm">Target: {target} XLM</span>
             <span className="text-gray-400 text-sm">Raised: {raised} XLM</span>
           </div>
           <div className="w-full bg-gray-700 rounded-full h-4 overflow-hidden">
             <div 
                className="bg-gradient-to-r from-green-400 to-blue-500 h-4 rounded-full transition-all duration-500" 
                style={{ width: `${Math.min((raised / target) * 100, 100)}%` }}
             ></div>
           </div>
        </div>

        {!address ? (
          <div className="flex flex-col gap-4">
            <button
              onClick={connect}
              disabled={isConnecting}
              className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 px-4 rounded-lg transition-colors flex items-center justify-center"
            >
              {isConnecting ? 'Connecting...' : 'Connect Wallet'}
            </button>
            {walletError && <p className="text-red-400 text-sm text-center">{walletError}</p>}
          </div>
        ) : (
          <div className="flex flex-col gap-4">
            <div className="bg-gray-700/50 p-3 rounded-lg flex justify-between items-center border border-gray-600">
              <span className="text-sm truncate mr-4">
                {address.substring(0, 6)}...{address.substring(address.length - 4)}
              </span>
              <button 
                onClick={disconnect}
                className="text-xs bg-gray-600 hover:bg-gray-500 px-3 py-1 rounded transition-colors"
              >
                Disconnect
              </button>
            </div>

            <div className="mt-4">
              <label className="block text-sm font-medium text-gray-400 mb-2">
                Donation Amount (XLM)
              </label>
              <input
                type="number"
                value={amount}
                onChange={(e) => setAmount(e.target.value)}
                className="w-full bg-gray-700 border border-gray-600 rounded-lg px-4 py-3 text-white focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all"
                placeholder="10"
              />
            </div>

            <button
              onClick={handleDonate}
              disabled={status === 'pending' || !amount}
              className={`w-full font-bold py-3 px-4 rounded-lg transition-all ${
                status === 'pending' 
                  ? 'bg-blue-800 cursor-not-allowed text-gray-300' 
                  : 'bg-gradient-to-r from-blue-500 to-purple-600 hover:from-blue-600 hover:to-purple-700 text-white shadow-lg hover:shadow-xl'
              }`}
            >
              {status === 'pending' ? (
                <span className="flex items-center justify-center gap-2">
                  <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Processing...
                </span>
              ) : 'Donate'}
            </button>

            {status === 'success' && (
              <div className="bg-green-900/40 border border-green-500 p-3 rounded-lg text-green-400 text-sm text-center">
                Transaction Successful! Thank you for your donation.
              </div>
            )}

            {(status === 'fail' || error) && (
              <div className="bg-red-900/40 border border-red-500 p-3 rounded-lg text-red-400 text-sm text-center break-words">
                {error || 'Transaction Failed'}
              </div>
            )}

            {status === 'pending' && (
              <div className="bg-blue-900/40 border border-blue-500 p-3 rounded-lg text-blue-400 text-sm text-center">
                Transaction Status: Pending (awaiting network confirmation)
              </div>
            )}

          </div>
        )}
      </div>
    </div>
  );
}
